      data: {
        companyId: BigInt(companyId),
        name: dto.name,
        progress,
        deliverableDesc: dto.deliverableDesc,
        allowedFormats: dto.allowedFormats ?? undefined,
        category: dto.category,
        sortOrder: dto.sortOrder ?? 0,
      },
    });
